update swm_floating_wage set monthly_performance_salary = case when production_factor * quality_factor < 0.9 then
round(target_performance_pay * 0.9 * isnull(assessment_coefficient,1),2)
else round(target_performance_pay * production_factor * quality_factor * isnull(assessment_coefficient,1),2) end,

allocate_performance_pay = case when production_factor * quality_factor < 0.9 then
round(target_performance_pay * 0.9 * isnull(assessment_coefficient,1),2)
else  round(target_performance_pay * production_factor * quality_factor * isnull(assessment_coefficient,1),2) end,

wages_payable = case when production_factor * quality_factor < 0.9 then
round(target_performance_pay * 0.9 * isnull(assessment_coefficient,1) + pre_tax_withheld,2)
else round(target_performance_pay * production_factor * quality_factor * isnull(assessment_coefficient,1)+pre_tax_withheld,2) end,

net_payment=case when production_factor * quality_factor < 0.9 then round(target_performance_pay * 0.9 * isnull(assessment_coefficient,1)+pre_tax_withheld + after_tax_withheld,2)
else round(target_performance_pay * production_factor * quality_factor * isnull(assessment_coefficient,1) + pre_tax_withheld + after_tax_withheld,2) end
where enabled_flag = 1 and frozen_flag = 0




            and income_period = #{criteria.period, jdbcType = VARCHAR}




            and id = #{criteria.id, jdbcType = BIGINT}

